import org.junit.jupiter.api.Test;
import java.util.Arrays;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void basic() {
        int[] nums = {1, 1, 2, 3, 3};
        int k = new Solution().removeDuplicates(nums);
        assertEquals(3, k);
        assertArrayEquals(new int[]{1, 2, 3}, Arrays.copyOfRange(nums, 0, k));
    }

    @Test
    void noDuplicates() {
        int[] nums = {1, 2, 3, 4, 5};
        int k = new Solution().removeDuplicates(nums);
        assertEquals(5, k);
        assertArrayEquals(new int[]{1, 2, 3, 4, 5}, Arrays.copyOfRange(nums, 0, k));
    }

    @Test
    void allSame() {
        int[] nums = {7, 7, 7, 7};
        int k = new Solution().removeDuplicates(nums);
        assertEquals(1, k);
        assertArrayEquals(new int[]{7}, Arrays.copyOfRange(nums, 0, k));
    }

    @Test
    void single() {
        int[] nums = {42};
        int k = new Solution().removeDuplicates(nums);
        assertEquals(1, k);
        assertArrayEquals(new int[]{42}, Arrays.copyOfRange(nums, 0, k));
    }

    @Test
    void empty() {
        int[] nums = {};
        int k = new Solution().removeDuplicates(nums);
        assertEquals(0, k);
    }

    @Test
    void negativeValues() {
        int[] nums = {-3, -3, -1, 0, 0, 2};
        int k = new Solution().removeDuplicates(nums);
        assertEquals(4, k);
        assertArrayEquals(new int[]{-3, -1, 0, 2}, Arrays.copyOfRange(nums, 0, k));
    }

    @Test
    void twoPairs() {
        // adversarial: every element is duplicated exactly once
        int[] nums = {1, 1, 2, 2, 3, 3, 4, 4};
        int k = new Solution().removeDuplicates(nums);
        assertEquals(4, k);
        assertArrayEquals(new int[]{1, 2, 3, 4}, Arrays.copyOfRange(nums, 0, k));
    }
}
